export default function buildSearchSortControlsProps({
  t,
  q,
  setQ,
  openOnly,
  drop,
  setDrop,
  results,
  headAutoOpenRef,
  setHeadPinned,
  setHeadHidden,
  getScrollEl,
  data,
  pushNavState,
  setTopicFilterId,
  setSel,
  setThreadRoot,
  openThreadForPost,
  sortOpen,
  setSortOpen,
  videoFeedOpen,
  setVideoFeedUserSortLocked,
  setFeedSort,
  sel,
  inboxOpen,
  inboxTab,
  profileBranchMode,
  setPostSort,
  setTopicSort,
  starMode,
  setStarMode,
  questEnabled,
  questBtnClass,
  openQuests,
  onCommitSortChange,
}) {
  return {
    t,
    q,
    setQ,
    openOnly,
    drop,
    setDrop,
    results,
    headAutoOpenRef,
    setHeadPinned,
    setHeadHidden,
    getScrollEl,
    data,
    pushNavState,
    setTopicFilterId,
    setSel,
    setThreadRoot,
    openThreadForPost,
    sortOpen,
    setSortOpen,
    videoFeedOpen,
    setVideoFeedUserSortLocked,
    setFeedSort,
    sel,
    forcePostSort:
      profileBranchMode === 'posts' ||
      (inboxOpen && String(inboxTab || 'messages') !== 'messages'),
    setPostSort,
    setTopicSort,
    starMode,
    setStarMode,
    questEnabled,
    questBtnClass,
    openQuests,
    onCommitSortChange,
  }
}
